function calculate({
    householdIncome, householdSize, zipCode,
    housingStability, healthNeeds, employmentStatus,
    caregiverBurden, transportationAccess, ageGroup, disabilityStatus
}) {
    const income = parseFloat(householdIncome);
    const size = parseInt(householdSize);
    const housing = parseInt(housingStability);
    const health = parseInt(healthNeeds);
    const employment = parseInt(employmentStatus);
    const caregiver = parseInt(caregiverBurden);
    const transportation = parseInt(transportationAccess);
    const age = parseInt(ageGroup);
    const disability = parseInt(disabilityStatus);

    // Input validation and default values
    if (isNaN(income) || income < 0) return { error: 'Invalid Household Income' };
    if (isNaN(size) || size < 1) return { error: 'Invalid Household Size' };
    if (isNaN(housing) || isNaN(health) || isNaN(employment) || isNaN(caregiver) || isNaN(transportation) || isNaN(age) || isNaN(disability)) {
        return { error: 'Invalid selection for one or more categorical inputs' };
    }

    let baseNeedsScore = 0;
    const recommendedResources = [];

    // --- 1. Core Needs Assessment --- 
    // Income contribution to need (higher income, lower need)
    // Max income for 'high need' threshold, e.g., $4000/month for calculation scaling
    const incomeMaxConsideration = 4000;
    const incomeWeightedNeed = Math.max(0, 40 - (income / incomeMaxConsideration) * 40); // 0 income -> 40 pts, 4000 income -> 0 pts
    baseNeedsScore += incomeWeightedNeed;
    if (income < 2000) recommendedResources.push('Financial Assistance');

    // Household Size contribution
    baseNeedsScore += (size - 1) * 5; // First person is baseline, each additional adds 5 points
    if (size > 3 && income < 3000) recommendedResources.push('Food Security Programs');

    // Housing Stability
    const housingScores = [0, 15, 30]; // Stable, At-risk, Homeless
    baseNeedsScore += housingScores[housing];
    if (housing > 0) recommendedResources.push('Housing Support');

    // Health Needs
    const healthScores = [0, 8, 18, 25]; // None, Minor, Chronic, Urgent
    baseNeedsScore += healthScores[health];
    if (health > 1) recommendedResources.push('Health & Medical Services');
    if (health === 3) recommendedResources.push('Emergency Health Support', 'Mental Health Services');

    // Employment Status
    const employmentScores = [0, 10, 20]; // Employed, Underemployed, Unemployed
    baseNeedsScore += employmentScores[employment];
    if (employment > 0) recommendedResources.push('Employment & Job Training');

    // Caregiver Burden
    const caregiverScores = [0, 7, 15]; // None, Moderate, High
    baseNeedsScore += caregiverScores[caregiver];
    if (caregiver > 0) recommendedResources.push('Caregiver Support Services');

    // Transportation Access
    const transportationScores = [0, 6, 12]; // Good, Limited, None
    baseNeedsScore += transportationScores[transportation];
    if (transportation > 0) recommendedResources.push('Transportation Assistance');

    // Age Group (adds specific needs, not general vulnerability in this scale)
    if (age === 1) recommendedResources.push('Child & Youth Services'); // Child/Youth
    if (age === 2) recommendedResources.push('Senior Support Services'); // Senior

    // Disability Status
    const disabilityScores = [0, 10];
    baseNeedsScore += disabilityScores[disability];
    if (disability === 1) recommendedResources.push('Disability Support Programs');
    if (disability === 1 && health > 1) recommendedResources.push('Specialized Medical Support');

    // --- 2. Normalize Personal Support Index --- 
    // Maximum theoretical base needs score (e.g., 0 income, 6 people, homeless, urgent health, unemployed, high caregiver, no transport, disability)
    const maxPossibleBaseNeedsScore = 40 + (6-1)*5 + 30 + 25 + 20 + 15 + 12 + 10; // Approx 167 for common max inputs
    const personalSupportIndex = Math.min(100, Math.round((baseNeedsScore / maxPossibleBaseNeedsScore) * 100));

    // --- 3. Estimate Program Eligibility Score --- 
    let eligibilityScore = 0;

    // Income and Household Size are primary drivers for most aid programs
    // Example: Federal Poverty Level (FPL) calculation is complex, so we'll approximate.
    // Assume higher income for a given size reduces eligibility, lower increases.
    const incomePerPerson = income / size;
    const eligibilityIncomeThreshold = 1800; // Example: monthly income per person below this starts to qualify for many programs

    if (incomePerPerson < eligibilityIncomeThreshold) {
        eligibilityScore += Math.min(50, (eligibilityIncomeThreshold - incomePerPerson) / eligibilityIncomeThreshold * 50);
    }

    // Add points for critical needs that often qualify for specific programs
    if (housing === 2) eligibilityScore += 20; // Homeless
    else if (housing === 1) eligibilityScore += 10; // At-risk

    if (health === 3) eligibilityScore += 15; // Urgent health needs
    else if (health === 2) eligibilityScore += 8; // Chronic health needs

    if (employment === 2) eligibilityScore += 10; // Unemployed

    if (disability === 1) eligibilityScore += 10; // Disability status

    eligibilityScore = Math.min(100, Math.round(eligibilityScore));

    // Deduplicate and format recommended resources
    const uniqueResources = [...new Set(recommendedResources)];
    const formattedResources = uniqueResources.length > 0 ? uniqueResources.join(', ') : 'No specific resource categories identified, but general support is always available.';

    return {
        supportIndex: personalSupportIndex,
        eligibilityScore: eligibilityScore,
        recommendedResources: formattedResources
    };
}
